detailed_optimizations.code_changes:
将更新 ey 和 ex 的循环进行合并，减少对 hz 的重复加载。同时，利用 OpenMP 并在内层循环应用 SIMD 向量化。具体代码修改如下：

```cpp
#pragma omp parallel
{
  for(t = 0; t < _PB_TMAX; t++)
  {
    // 1. 更新 ey[0][j]
    #pragma omp single
    {
      #pragma omp simd
      for (j = 0; j < _PB_NY; j++)
        ey[0][j] = _fict_[t];
    }

    // 2. 融合更新 ey 和 ex
    #pragma omp for collapse(2) schedule(static)
    for (i = 1; i < _PB_NX; i++) {
      for (j = 1; j < _PB_NY; j++) {
        // 融合计算，提升 L1/L2 缓存复用
        ey[i][j] = ey[i][j] - SCALAR_VAL(0.5)*(hz[i][j]-hz[i-1][j]);
        ex[i][j] = ex[i][j] - SCALAR_VAL(0.5)*(hz[i][j]-hz[i][j-1]);
      }
    }
    // 处理 ex 在 i=0 时的边界
    #pragma omp single
    {
      #pragma omp simd
      for (j = 1; j < _PB_NY; j++)
        ex[0][j] = ex[0][j] - SCALAR_VAL(0.5)*(hz[0][j]-hz[0][j-1]);
    }

    #pragma omp barrier

    // 3. 更新 hz
    #pragma omp for collapse(2) schedule(static)
    for (i = 0; i < _PB_NX - 1; i++) {
      for (j = 0; j < _PB_NY - 1; j++) {
        hz[i][j] = hz[i][j] - SCALAR_VAL(0.7)*(ex[i][j+1] - ex[i][j] + ey[i+1][j] - ey[i][j]);
      }
    }
    #pragma omp barrier
  }
}
```
